import Foundation

let score = 85
let hasBonus = true

// Multiple conditions
if score >= 90 {
    print("Grade: A")
} else if score >= 80 {
    print("Grade: B")
} else if score >= 70 {
    print("Grade: C")
} else {
    print("Grade: F")
}

// Combined conditions
if score > 80 && hasBonus {
    print("Excellent work with bonus!")
}

// Using where with if
let optionalValue: Int? = 10
if let value = optionalValue, value > 5 {
    print("Value \(value) is greater than 5")
}
